  function appendBubble(container, text, type) {
    const div = doc.createElement('div'); div.className = `fp-bubble fp-bubble-${type}`; div.textContent = text; container.appendChild(div);
  }
  function scrollToBottom(el) { setTimeout(() => { el.scrollTop = el.scrollHeight; }, 50); }

  renderHome();
