  }

  ct.addEventListener('change', (e) => {
    if (e.target.id === 'fp-model-select' && e.target.value) { root.querySelector('#fp-net-model').value = e.target.value; }

    if (e.target.id === 'fp-new-c-avatar-file') {
      const file = e.target.files[0];
      if (!file) return;
      const reader = new FileReader();
      reader.onload = function(evt) {
        const img = new Image();
        img.onload = function() {
          const canvas = doc.createElement('canvas'); const MAX_SIZE = 128; 
          let width = img.width, height = img.height;
          if (width > height) { if (width > MAX_SIZE) { height *= MAX_SIZE / width; width = MAX_SIZE; } }
          else { if (height > MAX_SIZE) { width *= MAX_SIZE / height; height = MAX_SIZE; } }
          canvas.width = width; canvas.height = height;
          const ctx = canvas.getContext('2d'); ctx.drawImage(img, 0, 0, width, height);
          win._fpTempAvatar = canvas.toDataURL('image/jpeg', 0.8);
          const prev = root.querySelector('#fp-avatar-preview');
          if(prev) { prev.src = win._fpTempAvatar; prev.style.display = 'block'; }
        }
        img.src = evt.target.result;
      };
      reader.readAsDataURL(file);
    }
  });

