      const hk = 'c_' + cid;
      if (!win._fpChats[hk]) win._fpChats[hk] = [];
      renderApp('微信'); return;
    }

    const appBtn = e.target.closest('.fp-app'); if (appBtn) { renderApp(appBtn.getAttribute('data-app')); return; }
    const backBtn = e.target.closest('.fp-back-btn'); if (backBtn) { renderHome(); return; }
    const eyeBtn = e.target.closest('.fp-eye-btn');
    if (eyeBtn) {
      isEyeCare = !isEyeCare; try { store.setItem(CFG.eyeKey, isEyeCare); } catch (err) {}
      if (isEyeCare) { root.classList.add('fp-eye-care'); eyeBtn.classList.add('active'); eyeBtn.innerText = 'ON'; } 
      else { root.classList.remove('fp-eye-care'); eyeBtn.classList.remove('active'); eyeBtn.innerText = 'OFF'; }
      return;
    }

    if (e.target.closest('#fp-set-save-time')) {
      const t = root.querySelector('#fp-set-time').value.trim(); const d = root.querySelector('#fp-set-date').value.trim(); const y = root.querySelector('#fp-set-year').value.trim();
      const status = root.querySelector('#fp-set-status');
      try { store.setItem(CFG.varTimeKey, t); store.setItem(CFG.varDateKey, d); store.setItem(CFG.varYearKey, y); updateOSClock(); 
        status.style.display = 'block'; status.innerHTML = '<b style="color:var(--dd-cyan)">关联已保存 ✔</b><br>已打通点结构解析映射引擎。'; } catch(err){}
    }

    if (e.target.closest('#fp-net-fetch')) {
      const fetchBtn = e.target.closest('#fp-net-fetch'); let baseUrl = root.querySelector('#fp-net-url').value.trim(); const key = root.querySelector('#fp-net-key').value.trim(); const status = root.querySelector('#fp-net-status');
      baseUrl = baseUrl.replace(/\/chat\/completions\/?$/, ''); root.querySelector('#fp-net-url').value = baseUrl;
      status.style.display = 'block'; status.innerHTML = '正在扫描神经网节点...'; fetchBtn.disabled = true;
      try {
        const res = await fetch(baseUrl + '/models', { method: 'GET', headers: { 'Authorization': `Bearer ${key}` } }); const data = await res.json();
        if (data && data.data && Array.isArray(data.data)) {
          const selectList = root.querySelector('#fp-model-select'); selectList.innerHTML = '<option value="">-- 🔽 在此下拉选取扫描出的模型 --</option>';
          let models = data.data.map(m => m.id);
          models.sort((a, b) => { const score = (x) => (x.includes('gemini')?10:0) + (x.includes('pro')?5:0) + (x.includes('gpt-4')?8:0); return score(b) - score(a); });
          models.forEach(m => { const opt = doc.createElement('option'); opt.value = m; opt.textContent = m; selectList.appendChild(opt); });
          status.innerHTML = `<b style="color:var(--dd-cyan)">扫描成功</b><br>发现 ${models.length} 个可用模型。`;
        } else throw new Error('API 响应格式不兼容');
      } catch (err) { status.innerHTML = `<b style="color:var(--dd-pink)">扫描失败</b><br>${err.message}`; } finally { fetchBtn.disabled = false; }
    }

    if (e.target.closest('#fp-net-save')) {
      const url = root.querySelector('#fp-net-url').value.trim(); const key = root.querySelector('#fp-net-key').value.trim(); const model = root.querySelector('#fp-net-model').value.trim(); const status = root.querySelector('#fp-net-status');
      try { store.setItem(CFG.urlKey, url); store.setItem(CFG.keyKey, key); store.setItem(CFG.modelKey, model); status.style.display = 'block'; status.innerHTML = '<b style="color:var(--dd-cyan)">配置已保存 ✔</b><br>请进入【讯息】开始通讯。'; } catch(err){}
    }

    // ===== 🌟 终极融合:微信发送(私聊+群聊),携带上下文与深层设定 =====
    if (e.target.closest('#fp-chat-send')) {
      const sendBtn = e.target.closest('#fp-chat-send'); const inputEl = root.querySelector('#fp-chat-input'); const msg = inputEl.value.trim(); const box = root.querySelector('#fp-chat-history');
      if (!msg) return;
      try { if (store.getItem(CFG.urlKey) || store.getItem(CFG.modelKey)) {} } catch(e){}
      const chatType = win._fpState.chatType || 'private';
      const chatId = win._fpState.chatId;
      const hk = (chatType === 'group' ? 'g_' : 'c_') + chatId;
      if (!chatId) { appendBubble(box, "[系统警告] 未指定通讯对象。", 'sys'); return; }
      let targets = [];
      if (chatType === 'group') {
        const g = win._fpGroups.find(x => x.id === chatId);
        if (!g) { appendBubble(box, "[系统警告] 群聊不存在。", 'sys'); return; }
        targets = (g.memberIds||[]).map(id => win._fpContacts.find(c => c.id === id)).filter(Boolean);
      } else {
        const c = win._fpContacts.find(c => c.id === chatId);
        if (!c) { appendBubble(box, "[系统警告] 联系人不存在。", 'sys'); return; }
        targets = [c];
      }
      if (targets.length === 0) { appendBubble(box, "[系统警告] 会话对方为空。", 'sys'); return; }

      let history = win._fpChats[hk] = win._fpChats[hk] || [];
      inputEl.value = ''; appendBubble(box, msg, 'user'); history.push({ role: 'user', content: msg, ts: Date.now() }); scrollToBottom(box);
      sendBtn.disabled = true; sendBtn.innerText = '...';
      const typingDiv = doc.createElement('div'); typingDiv.className = 'fp-bubble fp-bubble-ai'; typingDiv.innerHTML = '<span style="color:var(--dd-pink); font-style:italic;">对方正在输入...</span>'; box.appendChild(typingDiv); scrollToBottom(box);

      const mainContext = getMainChatContext();
      let chosen = targets[Math.floor(Math.random()*targets.length)]; // 群聊随机选一位
      const dynamicLore = fetchLoreFromST(chosen.bindKey);
      const allLore = chatType === 'group' ? targets.map(t => `- ${t.nick? t.nick+'(@'+t.bindKey+')':t.bindKey}: ${fetchLoreFromST(t.bindKey).slice(0,180)}`).join('\n') : dynamicLore;
      const memberList = chatType === 'group' ? targets.map(t => (t.nick||t.bindKey)).join('、') : chosen.nick;
      let sysPrompt = `【最高指令】
你现在的身份是“${chosen.bindKey}”${chosen.prompt ? `\n【玩家为你附加的额外设定】：${chosen.prompt}` : ''}。
${chatType === 'group' ? `\n【群聊成员设定】（本群成员：${memberList}，每次发言中当你以其中一员身份产生回复）：\n${allLore}\n` : `\n【你的底层档案与世界书设定】：\n${dynamicLore || '无特殊底层设定'}\n`}

【当前现实世界正在发生的剧情上下文】(主线，必须知晓以保持连贯)：
${mainContext}

【手机聊天回复规则】
你正在通过手机聊天软件发送文本消息。
1. 严格保持性格口吻，依"现实上下文"决定态度（如刚吵完架语气冷，正约会则留意你们所处环境、时间、地点）。
2. 必须简短、口语化，像真实手机聊天一样（1-3句即可）。
3. 不要带任何环境/动作/神态描写（也禁止用 *...* 或括号 (()）描述），只能输出纯文本对话。
${chatType === 'group' ? `4. 当前由你扮演"${chosen.nick||chosen.bindKey}"发言，请贴合TA在主线剧情当下最有可能的反应。` : '4. 不可暴露自己的真实姓名或网名给主角除非TA在主线已知道。'}`;

      const payloadMessages = [ { role: 'system', content: sysPrompt }, ...history.map(h => ({ role: h.role === 'assistant' ? 'assistant' : 'user', content: h.fromName && h.role==='assistant' ? `[${h.fromName}] ${h.content}` : h.content })), { role: 'user', content: msg } ];
