  // 辅助：从 contact 拼出"显示名 (@bindKey)"——上方 cmtSend 闭包调用
  function ownerbindKeyOrName(c) { return (c.nick ? c.nick + ' (@' + c.bindKey + ')' : c.bindKey); }

  // ===== 拖拽与缩放逻辑 =====
  let expanded = false, dragging = false, pressing = false;
  let startX = 0, startY = 0, startPosX = 0, startPosY = 0;
  let saved = null; try { saved = JSON.parse(store.getItem(CFG.posKey)); } catch (e) {}
  let pos = saved && typeof saved.x === 'number' && typeof saved.y === 'number' ? clampBtnPos(saved.x, saved.y) : { x: getVW() - CFG.btn - 20, y: getVH() - CFG.btn - 120 };
  root.style.left = pos.x + 'px'; root.style.top = pos.y + 'px';

  function applyPos(p) { pos = p; root.style.left = p.x + 'px'; root.style.top = p.y + 'px'; }
  function persist() { try { store.setItem(CFG.posKey, JSON.stringify(pos)); } catch(e){} }
  function expand() {
    const pw = Math.min(CFG.w, getVW() - CFG.margin * 2); const ph = Math.min(CFG.h, getVH() - CFG.margin * 2);
    let nx = clamp(pos.x + CFG.btn - pw, CFG.margin, getVW() - pw - CFG.margin); let ny = clamp(pos.y + CFG.btn - ph, CFG.margin, getVH() - ph - CFG.margin);
    applyPos({ x: nx, y: ny }); if (noAnim()) root.classList.add('fp-expanded'); else requestAnimationFrame(() => root.classList.add('fp-expanded')); expanded = true;
  }
  function collapse() {
    let nx = clamp(pos.x + CFG.w - CFG.btn, 0, getVW() - CFG.btn); let ny = clamp(pos.y + CFG.h - CFG.btn, 0, getVH() - CFG.btn);
    root.classList.remove('fp-expanded'); setTimeout(renderHome, 300); 
    if (noAnim()) { applyPos({ x: nx, y: ny }); persist(); } else { requestAnimationFrame(() => applyPos({ x: nx, y: ny })); setTimeout(persist, 420); } expanded = false;
  }
  function toggle() { expanded ? collapse() : expand(); }
  function evtXY(e) { return (e.touches && e.touches.length > 0) ? { x: e.touches[0].clientX, y: e.touches[0].clientY } : { x: e.clientX, y: e.clientY }; }
  function onDown(e) {
    if (e.button != null && e.button !== 0 && e.pointerType === 'mouse') return;
    pressing = true; dragging = false; const p = evtXY(e); startX = p.x; startY = p.y; startPosX = pos.x; startPosY = pos.y;
    doc.addEventListener('mousemove', onMove, { passive: false }); doc.addEventListener('mouseup', onUp); doc.addEventListener('touchmove', onMove, { passive: false }); doc.addEventListener('touchend', onUp); doc.addEventListener('touchcancel', onUp);
    if (e.cancelable) e.preventDefault();
  }
  function onMove(e) {
    if (!pressing) return; const p = evtXY(e); const dx = p.x - startX, dy = p.y - startY;
    if (!dragging && Math.hypot(dx, dy) > CFG.threshold) dragging = true;
    if (dragging) { if (e.cancelable) e.preventDefault(); root.classList.add('fp-dragging'); applyPos(expanded ? clampPanelPos(startPosX + dx, startPosY + dy) : clampBtnPos(startPosX + dx, startPosY + dy)); }
  }
  function onUp(e) {
    if (!pressing) return; pressing = false;
    doc.removeEventListener('mousemove', onMove); doc.removeEventListener('mouseup', onUp); doc.removeEventListener('touchmove', onMove); doc.removeEventListener('touchend', onUp); doc.removeEventListener('touchcancel', onUp);
    if (dragging) { root.classList.remove('fp-dragging'); if (!expanded) persist(); } else { if (!expanded) expand(); }
  }
  btn.addEventListener('mousedown', onDown); btn.addEventListener('touchstart', onDown, { passive: false });
  hd.addEventListener('mousedown', onDown); hd.addEventListener('touchstart', onDown, { passive: false });
  function handleMinimize(e) { e.stopPropagation(); e.preventDefault(); if (expanded) collapse(); }
  minBtn.addEventListener('mousedown', handleMinimize); minBtn.addEventListener('touchstart', handleMinimize, { passive: false }); minBtn.addEventListener('click', handleMinimize);
  ct.addEventListener('mousedown', (e) => { if (['INPUT', 'TEXTAREA', 'SELECT', 'OPTION'].includes(e.target.tagName) || e.target.closest('.fp-bubble')) e.stopPropagation(); });
  ct.addEventListener('touchstart', (e) => e.stopPropagation(), { passive: true });
  function onResize() { if (expanded) applyPos(clampPanelPos(pos.x, pos.y)); else { applyPos(clampBtnPos(pos.x, pos.y)); persist(); } if (noAnim()) root.classList.add('fp-no-anim'); else root.classList.remove('fp-no-anim'); }
  win.addEventListener('resize', onResize); win.addEventListener('orientationchange', onResize);

  win.FloatingPhoneAPI = { expand, collapse, toggle, setHTML(html) { ct.innerHTML = html; }, resetContent() { renderHome(); }, getState() { return { expanded, pos: { ...pos } }; } };
  if (window.toastr) window.toastr.success('DohnaPhone 终极沉浸版加载完毕 ✦');
})();
